import{_ as a,c as r,o as e,aj as i,ak as l,aK as d,aL as o,aM as s,aN as n,aO as h,aP as p}from"./chunks/framework.CoirRWyn.js";const x=JSON.parse('{"title":"1.5 使用深度研究","description":"","frontmatter":{},"headers":[],"relativePath":"module_1/1.5使用深度研究 [ Using deep research ].md","filePath":"module_1/1.5使用深度研究 [ Using deep research ].md"}'),_={name:"module_1/1.5使用深度研究 [ Using deep research ].md"};function c(m,t,g,u,b,A){return e(),r("div",null,[...t[0]||(t[0]=[i('<p><img src="'+l+'" alt="alt text"></p><h1 id="_1-5-使用深度研究" tabindex="-1">1.5 使用深度研究 <a class="header-anchor" href="#_1-5-使用深度研究" aria-label="Permalink to “1.5 使用深度研究”">​</a></h1><p><img src="'+d+'" alt="alt text"></p><h2 id="什么是深度研究" tabindex="-1">什么是深度研究？ <a class="header-anchor" href="#什么是深度研究" aria-label="Permalink to “什么是深度研究？”">​</a></h2><p>有时候，你希望 AI 不只是综合几个来源，而是综合几十个来源，并进行大量思考，给出对某个问题最深入、最全面的研究答案。</p><p>ChatGPT、Gemini、Claude 等主流 AI 聊天界面都提供了<strong>深度研究模式</strong>。这是一个非常有价值却常被低估的工具。</p><h2 id="深度研究的使用示例" tabindex="-1">深度研究的使用示例 <a class="header-anchor" href="#深度研究的使用示例" aria-label="Permalink to “深度研究的使用示例”">​</a></h2><p><img src="'+o+'" alt="alt text"></p><p>以&quot;规划万圣节鬼屋&quot;为例，你可以给 AI 提供详细的背景信息：</p><ul><li>所在地点</li><li>前院面积</li><li>期望的体验效果</li></ul><p>AI 会据此制定一个研究计划，思考需要查阅哪些类型的来源。</p><p><strong>研究流程示例：</strong><img src="'+s+'" alt="alt text"></p><ol><li>查询当地（如帕洛阿尔托）的许可规定和万圣节法规</li><li>阅读相关网页，综合已获取的信息</li><li>进一步搜索消防安全指南</li><li>搜索装饰创意</li></ol><p>研究过程会大致遵循原始计划，但也有灵活性——如果某个方向需要深入，它会继续挖掘。</p><p>经过数分钟的搜索后，AI 会生成一份详细的研究报告，涵盖结构与法规框架、安全注意事项等多个板块。</p><h2 id="深度研究与智能体-ai" tabindex="-1">深度研究与智能体 AI <a class="header-anchor" href="#深度研究与智能体-ai" aria-label="Permalink to “深度研究与智能体 AI”">​</a></h2><p>深度研究是<strong>智能体 AI（Agentic AI）</strong>的一个典型例子。在这个过程中，AI 模型有一定的自主决策能力，例如自行判断是否需要进行额外搜索。</p><h2 id="gemini-的特色功能" tabindex="-1">Gemini 的特色功能 <a class="header-anchor" href="#gemini-的特色功能" aria-label="Permalink to “Gemini 的特色功能”">​</a></h2><p>使用 Google Gemini 进行深度研究时，它可以将研究结果转化为： <img src="'+n+'" alt="alt text"></p><ul><li>网页</li><li>信息图表</li><li>其他多种形式</li></ul><p>例如，Gemini 生成的万圣节鬼屋规划网页包含：</p><ul><li>四个内容板块</li><li>预算饼图</li><li>噪音法规可视化图表</li><li>可用于活动规划的检查清单</li></ul><h2 id="深度研究的工作原理" tabindex="-1">深度研究的工作原理 <a class="header-anchor" href="#深度研究的工作原理" aria-label="Permalink to “深度研究的工作原理”">​</a></h2><p><img src="'+h+'" alt="alt text"></p><p>深度研究的一大优势是可以<strong>同时</strong>发起多个搜索，而不是逐一进行，因此在获取大量网页时效率极高。</p><h2 id="普通网络搜索-vs-深度研究" tabindex="-1">普通网络搜索 vs. 深度研究 <a class="header-anchor" href="#普通网络搜索-vs-深度研究" aria-label="Permalink to “普通网络搜索 vs. 深度研究”">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>推荐方式</th></tr></thead><tbody><tr><td>查找附近评分高的健身房</td><td>普通网络搜索</td></tr><tr><td>查询迪拜本周天气</td><td>普通网络搜索</td></tr><tr><td>每日步数对长期健康的影响（需综合科学文献）</td><td>深度研究</td></tr><tr><td>天气对迪拜旅游业的影响（需多维度分析）</td><td>深度研究</td></tr></tbody></table><h2 id="三种信息获取方式对比" tabindex="-1">三种信息获取方式对比 <a class="header-anchor" href="#三种信息获取方式对比" aria-label="Permalink to “三种信息获取方式对比”">​</a></h2><table tabindex="0"><thead><tr><th>方式</th><th>来源数量</th><th>信息时效性</th><th>响应时间</th><th>适用场景</th></tr></thead><tbody><tr><td>预训练知识</td><td>无需联网</td><td>截止日期前</td><td>几秒</td><td>常见事实、定义、摘要</td></tr><tr><td>普通网络搜索</td><td>少量（几个）</td><td>较新</td><td>数秒至数十秒</td><td>实时信息、位置查询、小众信息</td></tr><tr><td>深度研究</td><td>大量（几十个以上）</td><td>最新</td><td>数分钟以上</td><td>复杂问题、多来源综合分析</td></tr></tbody></table><p><img src="'+p+'" alt="alt text"></p><p><strong>触发方式的区别</strong>：</p><ul><li>普通网络搜索：可由 AI 自动触发，也可由用户主动触发</li><li>深度研究：通常需要用户在界面中<strong>明确选择</strong>，AI 不会自动启动（否则你可能要等好几分钟才能得到回答）</li></ul><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h2><p>找信息是人们使用 AI 最常见的任务之一。你现在掌握了三条路径：</p><ol><li><strong>预训练知识</strong>：快速回答常见问题</li><li><strong>普通网络搜索</strong>：获取实时、位置相关或小众信息</li><li><strong>深度研究</strong>：深入综合多来源，回答复杂问题</li></ol><p>下一节将通过实践练习，帮助你建立对何时使用这三种方式的直觉。</p><hr><p>深度研究是目前 AI 工具中最被低估的功能之一，它本质上是把&quot;研究助理&quot;这个角色自动化了。</p><p><strong>时间成本的重新定价</strong>：深度研究需要等几分钟，这在习惯了即时响应的今天感觉很慢。但换个角度想：如果让你自己去读几十篇文章、综合出一份有结构的报告，可能需要几个小时甚至几天。几分钟换几小时，这个交易非常划算——前提是你问的问题值得这样深入研究。</p><p><strong>&quot;智能体 AI&quot;的意义</strong>：文中提到深度研究是智能体 AI 的典型例子，这个概念值得多想一想。普通 AI 是&quot;你问我答&quot;，而智能体 AI 是&quot;你给目标，我自己规划步骤去完成&quot;。这是一个质的飞跃——AI 从工具变成了能自主行动的协作者。深度研究只是这个方向的起点。</p><p><strong>什么问题适合深度研究？</strong> 一个简单的判断标准：如果这个问题的答案需要你综合多个不同来源、权衡不同观点，那就值得用深度研究。反之，如果只是查一个事实，普通搜索就够了。比如&quot;今天天气怎么样&quot;用普通搜索，&quot;气候变化对农业的长期影响&quot;就值得深度研究。</p><p><strong>Gemini 的可视化输出</strong>：把研究结果转化为信息图表和检查清单，这个功能看似是锦上添花，实际上解决了一个真实痛点——大段文字很难快速消化，而结构化的可视化输出能让你在几秒内抓住重点。这提醒我们：AI 的输出格式和内容本身同样重要，要学会要求 AI 以最适合你使用场景的形式呈现信息。</p>',42)])])}const f=a(_,[["render",c]]);export{x as __pageData,f as default};
